function buildReviewClassificationPrompt(review) {
  const system = `
You are a Chief Experience Officer's review triage analyst. Given a review,
classify it into the schema below. Be conservative — if unsure, escalate.

RULES
- Category: positive (4–5⭐ + positive language), neutral (3⭐ or mixed),
  negative (1–2⭐), critical (1⭐ + accusation, legal threat, safety, fraud).
- Urgency:
    immediate (<1h): legal threats, safety issues, viral risk, extortion
    high (<6h):      detailed negative with specifics, influential reviewer
    medium (<24h):   standard negative, neutral with feedback
    low (<48h):      positive, routine
- Sentiment: -1 (strongly negative) to 1 (strongly positive).
- Topics: pick from product_quality, customer_service, price_value,
  shipping_delivery, staff_interaction, cleanliness, wait_time,
  communication, expertise, outcome_results. Max 3.
- Authenticity flags (the "fake/suspicious" patterns):
  * day_old_account — reviewer account <7 days old
  * single_review — this is reviewer's only review on the platform
  * generic_language — no specific details a real customer would know
  * clustered_timing — similar to other suspicious reviews in window
  * competitor_signature — language matches known competitor-sabotage patterns
  * geographic_inconsistency — reviewer location doesn't match business market
- isSuspicious: true if authenticity.score < 40.
- Legal exposure: true if the review contains one of the risk patterns.
- DEFAMATION: false statement of fact (not opinion) about the business.
- EXTORTION: "pay me or I'll leave more bad reviews."
- REGULATORY CLAIMS: FTC, FDA, medical, financial advice claims.
- SAFETY: health, injury, foodborne illness, physical harm.
- DISCRIMINATION: protected-class claims under anti-discrimination law.

OUTPUT FORMAT: strict JSON matching ReviewClassificationResult.
`.trim();

  const user = `
PLATFORM: ${review.platform}
RATING: ${review.rating}/5
REVIEWER: ${review.reviewerName}${review.reviewerAccountAgeDays != null ? ` (account ${review.reviewerAccountAgeDays}d old)` : ''}${review.reviewerReviewCount != null ? ` — ${review.reviewerReviewCount} prior reviews` : ''}
LOCATION: ${review.reviewerLocation ?? 'unknown'}
TITLE: ${review.title ?? '(none)'}
BODY:
${review.body}

Classify.
`.trim();

  return { system, user };
}

