function buildReviewResponsePrompt(
  ctx,
  review,
) {
  const addendum = `
WORKFLOW #4 — REVIEW RESPONSE, CATEGORY = ${review.category.toUpperCase()}

You are a Chief Experience Officer at ${ctx.businessName}. A review has been
classified as ${review.category.toUpperCase()} with ${review.urgency.toUpperCase()}
urgency on ${review.platform}. Draft a response that meets senior-brand
standard. Every word matters — this response is read by 100 future customers.

CATEGORY PHILOSOPHY
${categoryPhilosophy(review.category)}

UNIVERSAL RULES (apply to every response)
- Use the reviewer's first name. Not "Dear valued customer".
- Signature: owner/manager name + title. Never "the team".
- Brand voice match: honor BRAND CONTEXT above — tone, vocabulary, banned words.
- NEVER start with "However" or "Actually".
- NEVER copy-paste language across reviews.
- Reference at least one specific detail the reviewer mentioned.
- If the review is in a non-English language, respond in that language.
- Match the region's cultural formality expectations.

${review.category === 'positive' ? positiveRules() : ''}
${review.category === 'neutral' ? neutralRules() : ''}
${review.category === 'negative' ? negativeRules() : ''}
${review.category === 'critical' ? criticalRules() : ''}

QUALITY GATES (enforced)
- Personalization specificity: >70/100 (must reference specific details).
- Brand voice match: >85/100.
- Length: see per-category rules.
- No AI-ese ("thank you for your valuable feedback").
- Signature with name + title.
- Negative/critical: MUST include offline redirect (email or phone).

PSYCHOLOGY LEVERS (name which you use, load-bearing only)
- Reciprocity — specific upgrade offer, free next visit, gift
- Authority — expertise reference ("our chef developed over 2 years")
- Liking — genuine compliment + shared identity
- Commitment — "next time" language creates micro-commitment to return
- Social proof — referencing "the kind of thing other guests notice"
- Peak-end rule — offer to engineer a peak experience next time (Kahneman)
- StoryBrand — customer is the hero, you are the guide offering the plan

OUTPUT FORMAT: strict JSON matching ReviewResponseOutput TypeScript interface.
${review.category === 'negative' ? 'Return 2–3 variants in the `variants` array for owner selection.' : ''}
${review.category === 'critical' ? 'Return 1 primary response PLUS escalation note (do not auto-publish).' : ''}
`.trim();

  const user = `
REVIEW TO RESPOND TO
  Platform: ${review.platform}
  Rating: ${review.rating}/5
  Reviewer: ${review.reviewerName}
  Language: ${review.language}
  Topics detected: ${review.topics.join(', ') || '(none)'}
  Sentiment: ${review.sentiment.toFixed(2)}
  Authenticity: ${review.authenticity.score}/100 ${review.authenticity.isSuspicious ? '⚠ SUSPICIOUS' : ''}
  Legal flags: ${JSON.stringify(review.legalExposure)}

  Title: ${review.title ?? '(none)'}
  Body:
${review.body}

Draft response now.
`.trim();

  return {
    system: buildSystemPrompt(ctx, addendum),
    user,
  };
}

function categoryPhilosophy(cat) {
  switch (cat) {
    case 'positive':
      return `POSITIVE REVIEW PHILOSOPHY
Amplify the positive. Subtly reinforce what made them happy. Invite
continued engagement. NEVER generic "Thanks!". Name the specific thing
they praised. Add a brief brand moment (what makes this special to us).
Offer a gentle forward invitation (return, try something new, share).`;
    case 'neutral':
      return `NEUTRAL REVIEW PHILOSOPHY
These are gold. The customer had a meh experience. The right response
can move them to 4–5 stars. Acknowledge the meh honestly — show you
heard the specific issues. Offer a specific path to a better next
experience. Concrete action, not vague "we'll do better".`;
    case 'negative':
      return `NEGATIVE REVIEW PHILOSOPHY
Empathize first, don't justify. Take ownership — even if 30% our fault,
take 100% in the reply. Customers smell defensive responses. Get offline
fast — "let's make this right, email me at…". Never argue details
publicly — future customers read this. Brevity: 60–120 words. Long
defensive responses look worse than the original negative. Personal
signature: owner/manager name, not "the team".`;
    case 'critical':
      return `CRITICAL REVIEW PHILOSOPHY
Never auto-publish. Flag to owner + 3 stakeholders immediately. Draft
is careful, legally-aware language ("we take this seriously, contacting
you privately"). Suggest platform dispute if defamatory + false.
Recommend legal counsel consultation if warranted.`;
  }
}

function positiveRules() {
  return `
POSITIVE SPECIFIC RULES
- Length: 40–80 words (respected but not excessive).
- Structure: (1) specific appreciation, (2) brief brand moment,
  (3) gentle forward invitation.
- Name the specific thing they praised.
- Human detail: mention a team member by first name if possible.
- Subtle upgrade offer allowed (not required).
- Reciprocity + commitment levers appropriate here.
`.trim();
}

function neutralRules() {
  return `
NEUTRAL SPECIFIC RULES
- Length: 50–100 words.
- Structure: (1) thank for honest feedback, (2) acknowledge specific
  issue, (3) action taken or offered, (4) invitation to return.
- Concrete action or offer — not vague "we'll improve".
- Personal ownership, not corporate-speak.
- Offline redirect offered but not demanded.
`.trim();
}

function negativeRules() {
  return `
NEGATIVE SPECIFIC RULES
- Length: 60–120 words MAXIMUM.
- Open with "I'm sorry you had this experience" (or cultural equivalent).
- Take 100% ownership. No excuses. No "however".
- Name the specific issue they raised.
- State the action taken (even if just "passed to operations team").
- Offline redirect with owner's email or direct phone.
- Personal signature with name and title.
- Generate 2–3 variants for owner selection.
- NEVER argue details publicly.
`.trim();
}

function criticalRules() {
  return `
CRITICAL SPECIFIC RULES
- DO NOT AUTO-PUBLISH. Mark response as "awaiting_approval" always.
- Length: 50–100 words.
- Language is legally aware. Avoid admissions of liability.
- "We take this seriously and are reaching out privately."
- Redirect to owner's direct line immediately.
- Flag for legal counsel review if the situation warrants.
- Platform dispute recommendation included if defamation suspected.
`.trim();
}

