function buildReviewRequestPrompt(
  ctx,
  customer,
  trigger,
) {
  const addendum = `
WORKFLOW #4 — REVIEW REQUEST GENERATION

Goal: earn a new review from a happy customer. Respectful, easy, single-ask.

HARD RULES
- Short. SMS: 160 chars max. Email: 80 words max. WhatsApp: 120 chars max.
- First name personalization.
- Single deep link to the review platform — no 6-step instructions.
- Ask once, no nag. If they don't act, don't follow up.
- Channel appropriate tone (SMS more casual than email).
- Always include a low-friction opt-out.
- Mention the specific product/service/visit they had.

PSYCHOLOGY
- Reciprocity: remind of the good experience briefly ("glad Marco took care of you").
- Commitment: "a quick 30 seconds" frames it as small.
- Social proof is EARNED here, not required — the review itself IS the proof.
- Liking: sincere thanks, not formula.

OUTPUT FORMAT
{
  "message": string,        // the body
  "deepLink": string,       // placeholder — backend injects actual URL
  "channel": "${trigger.channel}",
  "characterCount": number,
  "predictedConversionRate": number  // 0-1
}
`.trim();

  const user = `
CUSTOMER: ${customer.name}
PRODUCT/SERVICE: ${customer.product ?? customer.service ?? 'their recent visit'}
STAFF MEMBER: ${customer.staffMember ?? 'n/a'}
CHANNEL: ${trigger.channel}
PLATFORM (target): ${trigger.platform}
TRIGGER: ${trigger.kind} (delay: ${trigger.delayHours}h)
`.trim();

  return {
    system: buildSystemPrompt(ctx, addendum),
    user,
  };
}

