function buildDisputePrompt(
  ctx,
  review,
  evidence,
) {
  const addendum = `
WORKFLOW #4 — PLATFORM DISPUTE GENERATION

Draft a platform-specific dispute for a review we believe is fake or
malicious. The tone is professional, evidence-led, not emotional. These
disputes are reviewed by platform ops teams who see thousands per week —
make ours easy to approve.

REQUIRED SECTIONS
1. Opening: one sentence stating why this review violates platform policy.
2. Evidence list: bulleted, each item factual and verifiable.
3. Business impact statement (brief).
4. Requested action: removal OR investigation.
5. Professional sign-off.

DO NOT
- Attack the reviewer personally.
- Speculate about motives beyond what evidence supports.
- Use emotional language.

OUTPUT FORMAT: strict JSON { subject, body, evidenceItems: string[], requestedAction: "removal" | "investigation" }
`.trim();

  const user = `
REVIEW
  Platform: ${review.platform}
  Reviewer: ${review.reviewerName}
  Rating: ${review.rating}/5
  Body: ${review.body}

EVIDENCE
  Reviewer account age: ${evidence.reviewerAccountAge} days
  Reviewer history: ${evidence.reviewerHistory} reviews total
  Clustered suspicious timings: ${evidence.clusteredTimings.join(', ') || '(none)'}
  Transaction verification: ${evidence.transactionVerification}
  Content flags: ${evidence.contentFlags.join(', ') || '(none)'}
`.trim();

  return {
    system: buildSystemPrompt(ctx, addendum),
    user,
  };
}

